<?php $adminTitle='Business Academy Overview';require_once __DIR__.'/../includes/business-admin-header.php';$counts=['Published programs'=>(int)$pdo->query("SELECT COUNT(*) FROM business_courses WHERE status='Published'")->fetchColumn(),'Case-study lessons'=>(int)$pdo->query('SELECT COUNT(*) FROM business_lessons')->fetchColumn(),'Practical activities'=>(int)$pdo->query('SELECT COUNT(*) FROM business_activities')->fetchColumn(),'Certificates issued'=>(int)$pdo->query('SELECT COUNT(*) FROM business_certificates')->fetchColumn()];$recent=$pdo->query('SELECT p.*,l.full_name,c.title course_title,bl.title lesson_title FROM business_progress p JOIN learners l ON l.id=p.learner_id JOIN business_courses c ON c.id=p.course_id LEFT JOIN business_lessons bl ON bl.id=p.lesson_id ORDER BY p.updated_at DESC LIMIT 8')->fetchAll();?>
<div class="admin-top"><div><p class="eyebrow">Business AI Academy</p><h1>Capability, progress, and credentials.</h1></div><a class="btn btn-premium" href="business-courses.php?new=1">Create business course</a></div><div class="row g-4 mb-4"><?php foreach($counts as $label=>$count):?><div class="col-md-6 col-xl-3"><div class="glass-card stat-admin"><span><?=e($label)?></span><strong><?=$count?></strong></div></div><?php endforeach?></div><div class="glass-card table-responsive"><h2>Recent business learning</h2><table class="table table-dark"><tr><th>Learner</th><th>Program</th><th>Lesson</th><th>Status</th><th>Updated</th></tr><?php foreach($recent as $row):?><tr><td><?=e($row['full_name'])?></td><td><?=e($row['course_title'])?></td><td><?=e($row['lesson_title']??'Practical activity')?></td><td><?=e($row['status'])?></td><td><?=e(date('M j, Y',strtotime($row['updated_at'])))?></td></tr><?php endforeach?></table></div>
